package com.hospital.management.model;import java.math.BigDecimal;import java.time.LocalDateTime;/** A server-calculated charge line belonging to a bill. */public class BillItem{private Long billItemId,billId;private String itemType,description;private BigDecimal quantity,unitPrice,lineTotal;private LocalDateTime createdAt;public Long getBillItemId(){return billItemId;}public void setBillItemId(Long v){billItemId=v;}public Long getBillId(){return billId;}public void setBillId(Long v){billId=v;}public String getItemType(){return itemType;}public void setItemType(String v){itemType=v;}public String getDescription(){return description;}public void setDescription(String v){description=v;}public BigDecimal getQuantity(){return quantity;}public void setQuantity(BigDecimal v){quantity=v;}public BigDecimal getUnitPrice(){return unitPrice;}public void setUnitPrice(BigDecimal v){unitPrice=v;}public BigDecimal getLineTotal(){return lineTotal;}public void setLineTotal(BigDecimal v){lineTotal=v;}public LocalDateTime getCreatedAt(){return createdAt;}public void setCreatedAt(LocalDateTime v){createdAt=v;}}
